export class PersistentVector<T> {
  private static readonly BRANCH_FACTOR = 32;
  private static readonly SHIFT = 5; // log2(32)

  private readonly root: Node<T> | null;
  private readonly tail: T[];
  private readonly size: number;

  private constructor(root: Node<T> | null, tail: T[], size: number) {
    this.root = root;
    this.tail = tail;
    this.size = size;
  }

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>(null, [], 0);
  }

  get size(): number {
    return this.size;
  }

  get(i: number): T {
    if (i < 0 || i >= this.size) {
      throw new Error(`Index ${i} out of range for vector of size ${this.size}`);
    }

    const tailStart = this.size - this.tail.length;
    if (i >= tailStart) {
      return this.tail[i - tailStart];
    }

    return this.pathGet(this.root!, i, PersistentVector.SHIFT);
  }

  private pathGet(node: Node<T>, index: int, shift: int): T {
    if (shift === 0) {
      return node.arr[index];
    }
    const bit = (index >>> shift) & 0x1f;
    return this.pathGet(node.arr[bit]!, index, shift - PersistentVector.SHIFT);
  }

  push(value: T): PersistentVector<T> {
    const newSize = this.size + 1;
    const newTail = [...this.tail, value];

    if (this.tail.length < PersistentVector.BRANCH_FACTOR) {
      return new PersistentVector<T>(this.root, newTail, newSize);
    }

    // Tail is full: push tail into tree, start new tail
    const newRoot = this.pushTail(this.root, this.tail, 0, PersistentVector.SHIFT);
    return new PersistentVector<T>(newRoot, [value], newSize);
  }

  private pushTail(
    node: Node<T> | null,
    tail: T[],
    level: int,
    shift: int
  ): Node<T> {
    if (level === shift) {
      // Leaf level: create a new node with the tail
      const arr: T[] = new Array(PersistentVector.BRANCH_FACTOR);
      for (let i = 0; i < tail.length; i++) {
        arr[i] = tail[i];
      }
      return new Node(arr);
    }

    const bit = (tail.length >>> level) & 0x1f;
    const child = node?.arr[bit] ?? null;
    const newChild = this.pushTail(child, tail, level + PersistentVector.SHIFT, shift);

    const arr: (Node<T> | null)[] = new Array(PersistentVector.BRANCH_FACTOR);
    if (node) {
      for (let i = 0; i < PersistentVector.BRANCH_FACTOR; i++) {
        arr[i] = node.arr[i];
      }
    }
    arr[bit] = newChild;
    return new Node(arr);
  }
}

class Node<T> {
  readonly arr: (T | Node<T> | null)[];

  constructor(arr: (T | Node<T> | null)[]) {
    this.arr = arr;
  }
}

