export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private handlers: { [K in keyof TEvents]?: Array<(...args: TEvents[K]) => void> } = {};

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    if (!this.handlers[name]) {
      this.handlers[name] = [];
    }
    this.handlers[name]!.push(handler);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.handlers[name];
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}

class MedianStream {
  private maxHeap: number[] = []; // max-heap for lower half
  private minHeap: number[] = []; // min-heap for upper half

  private heapifyUp(arr: number[], index: number, isMaxHeap: boolean): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      const shouldSwap = isMaxHeap
        ? arr[parentIndex] < arr[index]
        : arr[parentIndex] > arr[index];
      if (!shouldSwap) break;
      [arr[parentIndex], arr[index]] = [arr[index], arr[parentIndex]];
      index = parentIndex;
    }
  }

  private heapifyDown(arr: number[], index: number, isMaxHeap: boolean): void {
    const length = arr.length;
    while (true) {
      const leftIndex = 2 * index + 1;
      const rightIndex = 2 * index + 2;
      let swapIndex = index;

      if (leftIndex < length) {
        if (isMaxHeap
          ? arr[leftIndex] > arr[swapIndex]
          : arr[leftIndex] < arr[swapIndex]
        ) {
          swapIndex = leftIndex;
        }
      }
      if (rightIndex < length) {
        if (isMaxHeap
          ? arr[rightIndex] > arr[swapIndex]
          : arr[rightIndex] < arr[swapIndex]
        ) {
          swapIndex = rightIndex;
        }
      }
      if (swapIndex === index) break;
      [arr[index], arr[swapIndex]] = [arr[swapIndex], arr[index]];
      index = swapIndex;
    }
  }

  private pushHeap(arr: number[], value: number, isMaxHeap: boolean): void {
    arr.push(value);
    this.heapifyUp(arr, arr.length - 1, isMaxHeap);
  }

  private popHeap(arr: number[], isMaxHeap: boolean): number {
    if (arr.length === 0) throw new Error("Heap is empty");
    const top = arr[0];
    const last = arr.pop()!;
    if (arr.length > 0) {
      arr[0] = last;
      this.heapifyDown(arr, 0, isMaxHeap);
    }
    return top;
  }

  private peekHeap(arr: number[]): number {
    if (arr.length === 0) throw new Error("Heap is empty");
    return arr[0];
  }

  add(n: number): void {
    if (
      this.maxHeap.length === 0 ||
      n <= this.peekHeap(this.maxHeap)
    ) {
      this.pushHeap(this.maxHeap, n, true);
    } else {
      this.pushHeap(this.minHeap, n, false);
    }

    // Rebalance heaps so that size difference <= 1
    if (this.maxHeap.length > this.minHeap.length + 1) {
      this.pushHeap(this.minHeap, this.popHeap(this.maxHeap, true), false);
    } else if (this.minHeap.length > this.maxHeap.length) {
      this.pushHeap(this.maxHeap, this.popHeap(this.minHeap, false), true);
    }
  }

  median(): number {
    if (this.maxHeap.length === 0 && this.minHeap.length === 0) {
      throw new Error("No elements added yet");
    }
    if (this.maxHeap.length === this.minHeap.length) {
      return (this.peekHeap(this.maxHeap) + this.peekHeap(this.minHeap)) / 2;
    }
    return this.peekHeap(this.maxHeap);
  }
}

export { MedianStream };
